package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSetDateFormat_SetsDateStyleAndNullifiesDatePattern() throws Exception {
    // Arrange
    int style = 3;

    // Use reflection to set initial datePattern to non-null value
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    datePatternField.set(gsonBuilder, "initialPattern");

    // Use reflection to set initial dateStyle to a different value
    Field dateStyleField = GsonBuilder.class.getDeclaredField("dateStyle");
    dateStyleField.setAccessible(true);
    dateStyleField.setInt(gsonBuilder, DateFormat.SHORT);

    // Act
    GsonBuilder returned = gsonBuilder.setDateFormat(style);

    // Assert
    assertSame(gsonBuilder, returned, "setDateFormat should return the same GsonBuilder instance");
    assertEquals(style, dateStyleField.getInt(gsonBuilder), "dateStyle should be set to the given style");
    assertNull(datePatternField.get(gsonBuilder), "datePattern should be null after setDateFormat(int)");
  }
}
